@spec mm_wide_cc_spec  src=tests/specs/mm_wide_cc_spec.lua  loc=143  sha=8cc9255  cases=6
@exercises midiManager (h.mm)
@surface   mm:ccs, mm:modify, mm:delete
@harness   fakeReaper:bindTake

# Intent
  14-bit CC primitive: a fractional val on cc 0..31 splits to an MSB/LSB wire pair; the codec
  owns it, not a registry. see docs/midiManager.md § 14-bit CCs

# Helpers
  @fn freshTake(name)  @ 9-15
  @fn wireCCs(rp, take)  @ 18-30
      -- Raw wire CCs straight from REAPER, bypassing the codec's coalescing. cc-sorted.
  @fn readCCs(mm)  @ 32-40

# Cases
  @case 'fractional val (code 0..31) splits into an MSB-shaped / LSB-step wire pair'  [pure]  @ 44-62
  @case 'wide CC reads back as one coalesced fixed-point event (round-trip)'  [pure]  @ 66-81
  @case 'carrier-style value (14-bit around 8192) round-trips exactly'  [pure]  @ 85-97
  @case 'a lone code 0..31 on the wire (no +32 partner) stays a plain 7-bit CC'  [pure]  @ 101-112
  @case 'integer val is untouched: one message, no LSB companion'  [pure]  @ 116-126
  @case 'deleting a wide CC removes both wire lanes'  [pure]  @ 130-141

# Uses (outbound edges)
  @use call mm:ccs  @ 34
  @use call mm:modify  @ 48,70,90,120,135,139
  @use call mm:delete  @ 139

# Fields (r read / w write incl. constructor keys)
  @field r cc  @ 28,37,54,58,78,110
  @field w cc  @ 25,49,71,91,121,136
  @field w chan  @ 25,49,71,91,121,136
  @field w evType  @ 49,71,91,121,136
  @field w name  @ 44,66,85,101,116,130
  @field r ppq  @ 36,57,61
  @field w ppq  @ 25,49,71,91,121,136
  @field w reaper  @ 11
  @field w run  @ 45,67,86,102,117,131
  @field r shape  @ 56,60,80
  @field w shape  @ 25,49,71,136
  @field r val  @ 55,59,79,96,111,125
  @field w val  @ 25,49,71,91,121,136
